class FrameRange:
    """
    A range of frames [start_frame, end_frame), end exclusive.
    """

    def __init__(self, start_frame: int, end_frame: int):
        self.start_frame: int = start_frame
        self.end_frame: int = end_frame

    @staticmethod
    def from_duration(start_frame: int, duration_frames: int) -> "FrameRange":
        return FrameRange(start_frame, start_frame + duration_frames)

    def duration_frames(self) -> int:
        return self.end_frame - self.start_frame

    def __len__(self):
        return self.duration_frames()

    def __repr__(self):
        return self.__str__()

    def __str__(self):
        return f"Frames{self.frame_interval()}"

    def frame_interval(self):
        return f"[{self.start_frame}➜{self.end_frame})"

    def __eq__(self, other):
        return isinstance(other, FrameRange) and self.start_frame == other.start_frame and self.end_frame == other.end_frame

    def __hash__(self):
        return hash((self.start_frame, self.end_frame))

    def __contains__(self, frame: int) -> bool:
        return self.start_frame <= frame < self.end_frame

    def __iter__(self):
        return iter(range(self.start_frame, self.end_frame))

    def would_split_into_two_ranges(self, frame: int) -> bool:
        """True if frame is strictly inside this range (not equal to its
        start), i.e. a valid point to split at."""
        return self.start_frame < frame < self.end_frame

    def overlaps(self, your: "FrameRange") -> bool:
        not_entirely_before_you = not self.end_frame <= your.start_frame
        not_entirely_after_you = not your.end_frame <= self.start_frame
        return not_entirely_before_you and not_entirely_after_you

    def contains_range(self, other: "FrameRange") -> bool:
        """True if `other` falls entirely inside this range.

        A zero-width `other` (e.g. a ResultOfCutOp marker) needs its own
        rule: touching one of this range's edges isn't "inside" -- a
        marker sitting exactly at frame 10 isn't inside [0,10) OR [10,20),
        it's the boundary BETWEEN them, so a remove() targeting either
        side must leave it alone. It only counts as contained when it's
        strictly between this range's edges (same "strictly inside" rule
        would_split_into_two_ranges uses), UNLESS `self` is itself that
        same zero-width point -- the one legitimate way to target a
        marker for removal is a zero-width range at its exact position
        (see tools/remove_result._delete_clip_id)."""
        other_is_zero_width = other.is_zero_width()
        if other_is_zero_width:
            self_is_zero_width = <|fim_middle|>
            if self_is_zero_width:
                return self.start_frame == other.start_frame
            return self.start_frame < other.start_frame < self.end_frame
        return self.start_frame <= other.start_frame and other.end_frame <= self.end_frame

    def intersection(self, other: "FrameRange") -> "FrameRange | None":
        start = max(self.start_frame, other.start_frame)
        end = min(self.end_frame, other.end_frame)
        return FrameRange(start, end) if start < end else None

    def split_at(self, frame: int) -> tuple["FrameRange", "FrameRange"]:
        if not self.would_split_into_two_ranges(frame):
            raise ValueError(f"cannot split {self} at frame {frame}: not strictly inside range")
        return FrameRange(self.start_frame, frame), FrameRange(frame, self.end_frame)

    def is_zero_width(self):
        return self.start_frame == self.end_frame
